.catalog-layout {
    display: flex;
    gap: 1.5rem;
    align-items: flex-start;
}

/* Sidebar */
.catalog-sidebar {
    width: 25%;
    min-width: 220px;
    background: #f8f9fa;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1.25rem;
    position: sticky;
    top: 1rem;
}

.catalog-sidebar h3 {
    margin-top: 0;
    margin-bottom: 1rem;
    font-size: 1.2rem;
    border-bottom: 2px solid #dee2e6;
    padding-bottom: 0.5rem;
}

.filter-section {
    margin-bottom: 1.25rem;
}

.filter-section h4 {
    margin: 0 0 0.5rem;
    font-size: 0.95rem;
    color: #495057;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    margin-bottom: 0.35rem;
    cursor: pointer;
    font-size: 0.9rem;
}

.filter-checkbox input[type="checkbox"] {
    cursor: pointer;
}

.price-inputs {
    display: flex;
    gap: 0.5rem;
}

.price-inputs label {
    flex: 1;
    font-size: 0.85rem;
    color: #6c757d;
}

.price-inputs input {
    width: 100%;
    padding: 0.35rem 0.5rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 0.9rem;
    margin-top: 0.2rem;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

/* Main content */
.catalog-main {
    flex: 1;
    min-width: 0;
}

.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    flex-wrap: wrap;
    gap: 0.5rem;
}

.sort-control {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    font-size: 0.9rem;
}

.sort-control select {
    padding: 0.35rem 0.5rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 0.9rem;
    background: #fff;
}

.results-info {
    font-size: 0.9rem;
    color: #6c757d;
}

/* Product grid */
.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1.25rem;
}

/* States */
.loading-container {
    display: flex;
    justify-content: center;
    padding: 3rem 0;
}

.loading-text {
    color: #6c757d;
    font-style: italic;
}

.empty-results {
    text-align: center;
