namespace sv_e5bf5bec3c0940f195bf7c6aa6d193c2.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_e5bf5bec3c0940f195bf7c6aa6d193c2.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

<div class="catalog-layout">
    <!-- Sidebar Filters -->
    <aside class="catalog-sidebar">
        <h3>Filters</h3>

        <div class="filter-section">
            <h4>Categories</h4>
            @if (categories is not null)
            {
                @foreach (var category in categories)
                {
                    <label class="filter-checkbox">
                        <input type="checkbox"
                               checked="@selectedCategories.Contains(category)"
                               @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                        @category
                    </label>
                }
            }
            else if (!hasError)
            {
                <p class="loading-text">Loading categories…</p>
            }
        </div>

        <div class="filter-section">
            <h4>Price Range</h4>
            <div class="price-inputs">
                <label>
                    Min
                    <input type="number" min="0" step="0.01" @bind="minPrice" placeholder="Min" />
                </label>
                <label>
                    Max
                    <input type="number" min="0" step="0.01" @bind="maxPrice" placeholder="Max" />
                </label>
            </div>
        </div>

        <div class="filter-section">
            <label class="filter-checkbox">
                <input type="checkbox" @bind="inStockOnly" />
                In Stock Only
            </label>
        </div>

        <div class="filter-actions">
            <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
            <button class="btn btn-secondary" @onclick="ClearFilters">Clear Filters</button>
        </div>
    </aside>

    <!-- Main Content -->
    <section class="catalog-main">
        @if (hasError)
        {
            <div class="alert alert-danger">
                <p>Something went wrong while loading products. Please try again.</p>
                <button class="btn btn-secondary" @onclick="RetryLoad">Retry</button>
            </div>
        }
        else
        {
            <!-- Toolbar -->
            <div class="catalog-toolbar">
                <div class="sort-control">
                    <label for="sort-select">Sort by:</label>
                    <select id="sort-select" @bind="sortBy" @bind:after="OnSortChanged">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A-Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <div class="results-info">
                    @if (searchResult is not null && searchResult.TotalCount > 0)
                    {
                        var first = (searchResult.Page - 1) * searchResult.PageSize + 1;
                        var last = Math.Min(searchResult.Page * searchResult.PageSize, searchResult.TotalCount);
                        <span>Showing @first–@last of @searchResult.TotalCount products</span>
                    }
                </div>
            </div>

            <!-- Products -->
            @if (isLoading)
            {
                <div class="loading-container">
                    <p class="loading-text">Loading products…</p>
                </div>
            }
            else if (searchResult is null || searchResult.Items.Count == 0)
            {
                <div class="empty-results">
                    <p>No products found matching your criteria.</p>
                    <button class="btn btn-secondary" @onclick="ClearFilters">Clear Filters</button>
                </div>
            }
            else
            {
                <div class="product-grid">
                    @foreach (var product in searchResult.Items)
                    {
                        <ProductCard Product="product"
                                     OnProductSelected="HandleProductSelected"
                                     OnAddToCart="HandleAddToCart" />
                    }
                </div>

                <!-- Pagination -->
                @if (totalPages > 1)
                {
                    <nav class="pagination" aria-label="Product pagination">
                        <button class="btn btn-page"
                                disabled="@(currentPage <= 1)"
                                @onclick="() => GoToPage(currentPage - 1)">
                            Previous
                        </button>
                        @for (var i = 1; i <= totalPages; i++)
                        {
                            var pageNum = i;
                            <button class="btn btn-page @(pageNum == currentPage ? "active" : "")"
                                    @onclick="() => GoToPage(pageNum)">
                                @pageNum
                            </button>
                        }
                        <button class="btn btn-page"
                                disabled="@(currentPage >= totalPages)"
                                @onclick="() => GoToPage(currentPage + 1)">
                            Next
                        </button>
                    </nav>
                }
            }
        }
    </section>
</div>

@code {
    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;

    private PagedResult<Product>? searchResult;
    private bool isLoading = true;
    private bool hasError;

    private int totalPages => searchResult is null || searchResult.PageSize == 0
        ? 0
        : (int)Math.Ceiling((double)searchResult.TotalCount / searchResult.PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        hasError = false;
        isLoading = true;

        try
        {
            var categoriesTask = categories is null
                ? ProductService.GetCategoriesAsync()
                : Task.FromResult(categories);

            var filter = BuildFilter();
            var searchTask = ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            categories = await categoriesTask;
            searchResult = await searchTask;
        }
        catch
        {
            hasError = true;
        }
        finally
        {
            isLoading = false;
        }
    }

    private ProductFilter BuildFilter()
    {
        return new ProductFilter(
            Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
            MinPrice: minPrice,
            MaxPrice: maxPrice,
            InStockOnly: inStockOnly
        );
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await SearchAsync();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        sortBy = "price_asc";
        await SearchAsync();
    }

    private async Task OnSortChanged()
    {
        currentPage = 1;
        await SearchAsync();
    }

    private async Task GoToPage(int page)
    {
        currentPage = page;
        await SearchAsync();
    }

    private async Task SearchAsync()
    {
        isLoading = true;
        hasError = false;

        try
        {
            var filter = BuildFilter();
            searchResult = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch
        {
            hasError = true;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync();
    }

    private void HandleProductSelected(Product product)
    {
        // Parent layout can handle navigation to /catalog/{product.Id}
    }

    private void HandleAddToCart(Product product)
    {
        // Cart integration point
    }
}

