toolArgs.file_text:
.catalog-layout {
    display: flex;
    gap: 1.5rem;
    align-items: flex-start;
}

/* Sidebar */
.catalog-sidebar {
    width: 25%;
    min-width: 220px;
    background: #f8f9fa;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1.25rem;
    position: sticky;
    top: 1rem;
}

.catalog-sidebar h3 {
    margin-top: 0;
    margin-bottom: 1rem;
    font-size: 1.2rem;
    border-bottom: 2px solid #dee2e6;
    padding-bottom: 0.5rem;
}

.filter-section {
    margin-bottom: 1.25rem;
}

.filter-section h4 {
    margin: 0 0 0.5rem;
    font-size: 0.95rem;
    color: #495057;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    margin-bottom: 0.35rem;
    cursor: pointer;
    font-size: 0.9rem;
}

.filter-checkbox input[type="checkbox"] {
    cursor: pointer;
}

.price-inputs {
    display: flex;
    gap: 0.5rem;
}

.price-inputs label {
    flex: 1;
    font-size: 0.85rem;
    color: #6c757d;
}

.price-inputs input {
    width: 100%;
    padding: 0.35rem 0.5rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 0.9rem;
    margin-top: 0.2rem;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

/* Main content */
.catalog-main {
    flex: 1;
    min-width: 0;
}

.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    flex-wrap: wrap;
    gap: 0.5rem;
}

.sort-control {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    font-size: 0.9rem;
}

.sort-control select {
    padding: 0.35rem 0.5rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 0.9rem;
    background: #fff;
}

.results-info {
    font-size: 0.9rem;
    color: #6c757d;
}

/* Product grid */
.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1.25rem;
}

/* States */
.loading-container {
    display: flex;
    justify-content: center;
    padding: 3rem 0;
}

.loading-text {
    color: #6c757d;
    font-style: italic;
}

.empty-results {
    text-align: center;
    padding: 3rem 1rem;
    color: #6c757d;
}

.alert {
    padding: 1rem 1.25rem;
    border-radius: 8px;
    margin-bottom: 1rem;
}

.alert-danger {
    background: #f8d7da;
    border: 1px solid #f5c2c7;
    color: #842029;
}

/* Pagination */
.pagination {
    display: flex;
    justify-content: center;
    gap: 0.35rem;
    margin-top: 1.5rem;
    flex-wrap: wrap;
}

/* Buttons */
.btn {
    padding: 0.5rem 1rem;
    border: 1px solid transparent;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
    transition: background-color 0.15s, opacity 0.15s;
}

.btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.btn-primary {
    background: #0d6efd;
    color: #fff;
    border-color: #0d6efd;
}

.btn-primary:hover:not(:disabled) {
    background: #0b5ed7;
}

.btn-secondary {
    background: #6c757d;
    color: #fff;
    border-color: #6c757d;
}

.btn-secondary:hover:not(:disabled) {
    background: #5c636a;
}

.btn-page {
    background: #fff;
    border-color: #dee2e6;
    color: #212529;
    min-width: 2.5rem;
    text-align: center;
}

.btn-page:hover:not(:disabled) {
    background: #e9ecef;
}

.btn-page.active {
    background: #0d6efd;
    color: #fff;
    border-color: #0d6efd;
}

